spec.inputArgumentsSchemaV2:
{
        "type": "object",
        "required": [],
        "properties": {
          "processInstanceId": {
            "type": "string",
            "description": "Unique BPMN process instance ID from UiPath Maestro for traceability. Format: UUID or alphanumeric. Generate a trace ID if not provided."
          },
          "receiptFiles": {
            "type": "array",
            "description": "One or more receipts, purchase orders, invoices, or financial documents (Excel, PDF, CSV, image). The agent will automatically read and extract all data from ALL attached files using the Analyze Files tool. Supports .xlsx, .pdf, .csv, .png, .jpg, .tiff formats. This is the PRIMARY input — no manual data entry needed. Attach multiple files for batch processing or cross-referencing (e.g., a PO file + matching receipt + delivery note).",
            "items": {
              "$ref": "#/definitions/job-attachment"
            }
          },
          "invoiceFile": {
            "description": "Scanned or digital PDF invoice. When present, use DeepRAG (multi-page/complex) or Analyze Files (simple 1-5 page) to extract all invoice data before reconciliation. Takes precedence over the structured invoice field.",
            "$ref": "#/definitions/job-attachment"
          },
          "batchInvoiceFile": {
            "description": "CSV file of historical invoices from this vendor for duplicate detection and pattern analysis. Columns: invoiceNumber, vendorId, amount, date, status. Use the Batch Transform tool to process this file when provided.",
            "$ref": "#/definitions/job-attachment"
          },
          "purchaseOrder": {
            "type": "object",
            "description": "Purchase Order as extracted by RPA from the ERP. Must include header and line-item details.",
            "required": [
              "poNumber",
              "vendorId",
              "vendorName",
              "currency",
              "totalAmount",
              "lineItems"
            ],
            "properties": {
              "poNumber": {
                "type": "string",
                "description": "Unique PO reference number (e.g., PO-2026-00123)."
              },
              "vendorId": {
                "type": "string",
                "description": "Internal vendor master ID."
              },
              "vendorName": {
                "type": "string",
                "description": "Legal vendor name in ERP."
              },
              "orderDate": {
                "type": "string",
                "description": "PO creation date (YYYY-MM-DD)."
              },
              "currency": {
                "type": "string",
                "description": "ISO 4217 currency code (e.g., USD, EUR)."
              },
              "totalAmount": {
                "type": "number",
                "description": "Total approved PO amount excl. tax."
              },
              "taxAmount": {
                "type": "number",
                "description": "Tax on PO. Defaults to 0 if omitted."
              },
              "paymentTerms": {
                "type": "string",
                "description": "Payment terms (e.g., NET30, 2/10-NET30). Used for early payment discount parsing."
              },
              "costCenter": {
                "type": "string",
                "description": "Cost center or department code."
              },
              "category": {
                "type": "string",
                "description": "Spend category (IT, Facilities, Marketing, Services, Goods). Drives approval routing and GL coding."
              },
              "lineItems": {
                "type": "array",
                "description": "PO line items. Each represents an ordered SKU or service.",
                "items": {
                  "type": "object",
                  "required": [
                    "lineNumber",
                    "description",
                    "quantityOrdered",
                    "unitPrice",
                    "totalPrice"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer",
                      "description": "Sequential line number from 1."
                    },
                    "itemCode": {
                      "type": "string",
                      "description": "SKU or service code."
                    },
                    "description": {
                      "type": "string",
                      "description": "Item or service description."
                    },
                    "quantityOrdered": {
                      "type": "number",
                      "description": "Quantity ordered."
                    },
                    "unitPrice": {
                      "type": "number",
                      "description": "Agreed unit price in PO currency."
                    },
                    "totalPrice": {
                      "type": "number",
                      "description": "quantityOrdered x unitPrice."
                    },
                    "glCode": {
                      "type": "string",
                      "description": "Existing GL account code from ERP. Used as medium-confidence fallback for GL coding suggestions."
                    },
                    "deliveryDate": {
                      "type": "string",
                      "description": "Expected delivery date (YYYY-MM-DD)."
                    }
                  }
                }
              }
            }
          },
          "goodsReceiptNote": {
            "type": "object",
            "description": "GRN confirming physical receipt of goods or service completion. If absent for goods POs, flag GRN_NOT_RECEIVED and check for accrual needs.",
            "properties": {
              "grnNumber": {
                "type": "string",
                "description": "Unique GRN reference number."
              },
              "receiptDate": {
                "type": "string",
                "description": "Date goods/services were received (YYYY-MM-DD)."
              },
              "receivedBy": {
                "type": "string",
                "description": "Name or employee ID of receiver."
              },
              "lineItems": {
                "type": "array",
                "description": "Received line items. Match by lineNumber to PO. Used for 3-way match and accrual detection.",
                "items": {
                  "type": "object",
                  "required": [
                    "lineNumber",
                    "quantityReceived"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer",
                      "description": "PO line number."
                    },
                    "itemCode": {
                      "type": "string",
                      "description": "SKU or service code."
                    },
                    "description": {
                      "type": "string",
                      "description": "Received item description."
                    },
                    "quantityReceived": {
                      "type": "number",
                      "description": "Actual quantity received and accepted."
                    },
                    "condition": {
                      "type": "string",
                      "description": "GOOD, DAMAGED, PARTIAL, or REJECTED."
                    }
                  }
                }
              }
            }
          },
          "invoice": {
            "type": "object",
            "description": "Vendor invoice as structured data from RPA (email/EDI/portal). Optional if invoiceFile is provided — PDF extraction takes precedence.",
            "properties": {
              "invoiceNumber": {
                "type": "string",
                "description": "Vendor invoice number."
              },
              "invoiceDate": {
                "type": "string",
                "description": "Invoice issue date (YYYY-MM-DD)."
              },
              "dueDate": {
                "type": "string",
                "description": "Payment due date (YYYY-MM-DD). Used for SLA and payment intelligence calculations."
              },
              "vendorId": {
                "type": "string",
                "description": "Vendor ID on invoice. Must match PO vendorId."
              },
              "poReference": {
                "type": "string",
                "description": "PO number on invoice. Must match purchaseOrder.poNumber."
              },
              "currency": {
                "type": "string",
                "description": "ISO 4217 currency code on invoice."
              },
              "subtotalAmount": {
                "type": "number",
                "description": "Invoice subtotal before tax. Used for tax compliance check."
              },
              "taxAmount": {
                "type": "number",
                "description": "Tax charged on invoice."
              },
              "totalAmount": {
                "type": "number",
                "description": "Total due including tax."
              },
              "paymentTerms": {
                "type": "string",
                "description": "Payment terms on invoice. Compare against PO terms; flag conflicts."
              },
              "bankDetails": {
                "type": "object",
                "description": "Vendor bank details. Flag BANK_DETAIL_CHANGE if different from vendor master.",
                "properties": {
                  "bankName": {
                    "type": "string"
                  },
                  "accountNumber": {
                    "type": "string"
                  },
                  "routingNumber": {
                    "type": "string"
                  }
                }
              },
              "lineItems": {
                "type": "array",
                "description": "Invoice line items. Match by lineNumber or description against PO lines.",
                "items": {
                  "type": "object",
                  "required": [
                    "description",
                    "quantity",
                    "unitPrice",
                    "totalPrice"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer"
                    },
                    "description": {
                      "type": "string"
                    },
                    "quantity": {
                      "type": "number"
                    },
                    "unitPrice": {
                      "type": "number"
                    },
                    "totalPrice": {
                      "type": "number"
                    }
                  }
                }
              }
            }
          },
          "approvalThresholds": {
            "type": "object",
            "description": "Approval thresholds and tolerance policies driving BPMN gateway routing.",
            "properties": {
              "autoApproveLimit": {
                "type": "number",
                "description": "Max invoice total for auto-approval without human review. Default: 1000."
              },
              "managerApprovalLimit": {
                "type": "number",
                "description": "Invoices above this need manager approval. Default: 10000."
              },
              "tolerancePercentage": {
                "type": "number",
                "description": "Acceptable variance % before flagging discrepancy. Default: 2."
              },
              "toleranceAmountFloor": {
                "type": "number",
                "description": "Minimum absolute difference that must also be exceeded to trigger discrepancy. Default: 5."
              }
            }
          },
          "vendorContext": {
            "type": "object",
            "description": "Vendor history and risk data from ERP/CRM. Powers vendor scorecard and fraud assessment.",
            "properties": {
              "riskRating": {
                "type": "string",
                "description": "Vendor risk: LOW, MEDIUM, HIGH, BLOCKED."
              },
              "historicalDiscrepancyRate": {
                "type": "number",
                "description": "% of past invoices with discrepancies (0-100). Used in scorecard."
              },
              "onTimeDeliveryRate": {
                "type": "number",
                "description": "% of POs delivered on time (0-100). Used in scorecard."
              },
              "isPreferredVendor": {
                "type": "boolean",
                "description": "True if on approved/preferred vendor list."
              },
              "openDisputeCount": {
                "type": "integer",
                "description": "Currently open disputes with this vendor."
              }
            }
          },
          "earlyPaymentPolicy": {
            "type": "object",
            "description": "Organization's early payment discount policy. Overrides terms parsed from invoice/PO payment terms string. Used to calculate payment intelligence output.",
            "properties": {
              "discountPercentage": {
                "type": "number",
                "description": "Discount % for early payment (e.g., 2 for 2%). Overrides parsed terms."
              },
              "discountDays": {
                "type": "integer",
                "description": "Days within which early payment discount applies (e.g., 10 for 2/10-NET30)."
              },
              "netDays": {
                "type": "integer",
                "description": "Total payment due days (e.g., 30 for NET30)."
              }
            }
          },
          "exchangeRates": {
            "type": "object",
            "description": "FX exchange rates for multi-currency normalization. Keys are ISO 4217 pairs joined by underscore (e.g., 'USD_EUR': 0.92). Provide when PO and invoice currencies differ.",
            "additionalProperties": {
              "type": "number"
            }
          },
          "glCodeMapping": {
            "type": "array",
            "description": "Organization GL code mapping rules for smart GL coding suggestions. Each entry maps keywords to a GL account code.",
            "items": {
              "type": "object",
              "required": [
                "keywords",
                "glCode",
                "accountName"
              ],
              "properties": {
                "keywords": {
                  "type": "array",
                  "description": "Keywords to match against line item descriptions (case-insensitive).",
                  "items": {
                    "type": "string"
                  }
                },
                "glCode": {
                  "type": "string",
                  "description": "GL account code to assign when keywords match."
                },
                "accountName": {
                  "type": "string",
                  "description": "Human-readable GL account name."
                },
                "category": {
                  "type": "string",
                  "description": "Spend category this GL code belongs to."
                }
              }
            }
          },
          "complianceRules": {
            "type": "object",
            "description": "Tax compliance rules for the transaction jurisdiction. Used to validate invoice tax amounts and flag non-compliant invoices.",
            "properties": {
              "jurisdiction": {
                "type": "string",
                "description": "Tax jurisdiction code (e.g., US-CA, UK, DE, AU)."
              },
              "standardTaxRate": {
                "type": "number",
                "description": "Expected tax rate % (e.g., 10 for 10% GST, 20 for 20% VAT)."
              },
              "taxExemptCategories": {
                "type": "array",
                "description": "Spend categories exempt from standard tax (e.g., Healthcare, Education). If PO category is exempt, expected tax = 0.",
                "items": {
                  "type": "string"
                }
              }
            }
          },
          "previousInvoiceNumbers": {
            "type": "array",
            "description": "Array of recent invoice numbers (last 90 days) from this vendor in ERP. Used for duplicate detection when batchInvoiceFile is not provided.",
            "items": {
              "type": "string"
            }
          },
          "processContext": {
            "type": "string",
            "description": "Free-text notes from upstream BPMN tasks or RPA robots (e.g., 'Invoice arrived 5 days late', 'GRN flagged partial delivery'). Used for contextual reasoning."
          }
        },
        "definitions": {
          "job-attachment": {
            "type": "object",
            "required": [
              "ID"
            ],
            "x-uipath-resource-kind": "JobAttachment",
            "properties": {
              "ID": {
                "type": "string",
                "description": "Orchestrator attachment key"
              },
              "FullName": {
                "type": "string",
                "description": "File name"
              },
              "MimeType": {
                "type": "string",
                "description": "The MIME type of the content, such as \"application/json\" or \"image/png\""
              },
              "Metadata": {
                "type": "object",
                "description": "Dictionary<string, string> of metadata",
                "additionalProperties": {
                  "type": "string"
                }
              }
            }
          }
        }
      }

spec.outputArgumentsSchemaV2:
{
        "type": "object",
        "required": [
          "matchStatus",
          "recommendation",
          "confidenceScore",
          "nextBpmnGateway",
          "reconciliationSummary",
          "discrepancies",
          "actionItems",
          "reasoning"
        ],
        "properties": {
          "processInstanceId": {
            "type": "string",
            "description": "Echo of processInstanceId from input for BPMN correlation. Generate a trace ID if input was not provided."
          },
          "matchStatus": {
            "type": "string",
            "description": "3-way match result. FULL_MATCH = exact alignment. WITHIN_TOLERANCE = variance within threshold. PARTIAL_MATCH = some lines match. MISMATCH = significant variance outside tolerance. CRITICAL_EXCEPTION = fraud, blocked vendor, duplicate, or missing critical document.",
            "enum": [
              "FULL_MATCH",
              "WITHIN_TOLERANCE",
              "PARTIAL_MATCH",
              "MISMATCH",
              "CRITICAL_EXCEPTION"
            ]
          },
          "recommendation": {
            "type": "string",
            "description": "Recommended next action for the BPMN gateway. AUTO_APPROVE = post and schedule payment. RETURN_TO_VENDOR = request corrected invoice. ESCALATE_TO_AP = AP team manual review. ESCALATE_TO_MANAGER = budget owner approval. BLOCK_PAYMENT = halt for fraud/compliance review.",
            "enum": [
              "AUTO_APPROVE",
              "RETURN_TO_VENDOR",
              "ESCALATE_TO_AP",
              "ESCALATE_TO_MANAGER",
              "BLOCK_PAYMENT"
            ]
          },
          "confidenceScore": {
            "type": "number",
            "description": "Agent confidence 0-100. Reduce by 20 for incomplete PDF extraction. Reduce by 10 per missing optional document. Scores below 60 should trigger human review."
          },
          "nextBpmnGateway": {
            "type": "string",
            "description": "Exact Maestro BPMN sequence flow label. Must be one of: auto_approve_path, ap_review_path, manager_approval_path, vendor_dispute_path, fraud_hold_path."
          },
          "reconciliationSummary": {
            "type": "object",
            "description": "Financial summary of the 3-way match.",
            "required": [
              "poAmount",
              "invoiceAmount",
              "varianceAmount",
              "variancePercentage",
              "currency",
              "isWithinTolerance"
            ],
            "properties": {
              "poAmount": {
                "type": "number",
                "description": "PO total excl. tax — the baseline reference amount."
              },
              "grnAmount": {
                "type": "number",
                "description": "Value of goods/services confirmed received via GRN. Null if no GRN."
              },
              "invoiceAmount": {
                "type": "number",
                "description": "Invoice total excl. tax."
              },
              "varianceAmount": {
                "type": "number",
                "description": "invoiceAmount minus poAmount. Positive = overbilled."
              },
              "variancePercentage": {
                "type": "number",
                "description": "Variance as % of PO amount. Positive = overbilled."
              },
              "currency": {
                "type": "string",
                "description": "Currency code for all amounts."
              },
              "isWithinTolerance": {
                "type": "boolean",
                "description": "True if variancePercentage is within configured tolerancePercentage."
              }
            }
          },
          "discrepancies": {
            "type": "array",
            "description": "All discrepancies found. Empty array if FULL_MATCH.",
            "items": {
              "type": "object",
              "required": [
                "discrepancyId",
                "type",
                "severity",
                "description"
              ],
              "properties": {
                "discrepancyId": {
                  "type": "string",
                  "description": "Sequential ID e.g. DISC-001."
                },
                "type": {
                  "type": "string",
                  "enum": [
                    "PRICE_VARIANCE",
                    "QUANTITY_VARIANCE",
                    "LINE_ITEM_MISSING",
                    "EXTRA_LINE_ITEM",
                    "CURRENCY_MISMATCH",
                    "VENDOR_MISMATCH",
                    "PO_REFERENCE_MISSING",
                    "DUPLICATE_INVOICE",
                    "BANK_DETAIL_CHANGE",
                    "TAX_DISCREPANCY",
                    "PAYMENT_TERMS_CONFLICT",
                    "GRN_NOT_RECEIVED",
                    "SPLIT_INVOICE_PATTERN",
                    "VELOCITY_ANOMALY"
                  ]
                },
                "severity": {
                  "type": "string",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH",
                    "CRITICAL"
                  ]
                },
                "lineNumber": {
                  "type": "integer",
                  "description": "PO line number. Null for header-level discrepancies."
                },
                "description": {
                  "type": "string",
                  "description": "Human-readable discrepancy explanation."
                },
                "poValue": {
                  "type": "string",
                  "description": "Expected value from PO."
                },
                "invoiceValue": {
                  "type": "string",
                  "description": "Actual value from invoice."
                },
                "impactAmount": {
                  "type": "number",
                  "description": "Financial impact in PO currency. Positive = overbilled."
                }
              }
            }
          },
          "actionItems": {
            "type": "array",
            "description": "Ordered action items for the next actor in the BPMN process.",
            "items": {
              "type": "object",
              "required": [
                "actionId",
                "owner",
                "priority",
                "description"
              ],
              "properties": {
                "actionId": {
                  "type": "string",
                  "description": "Sequential ID e.g. ACT-001."
                },
                "owner": {
                  "type": "string",
                  "description": "AP_TEAM, MANAGER, VENDOR, RPA_ROBOT, AGENT, or SYSTEM."
                },
                "priority": {
                  "type": "string",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH",
                    "URGENT"
                  ]
                },
                "description": {
                  "type": "string"
                },
                "dueDate": {
                  "type": "string",
                  "description": "Suggested due date (YYYY-MM-DD)."
                }
              }
            }
          },
          "paymentIntelligence": {
            "type": "object",
            "description": "Smart payment timing to capture early payment discounts and manage cash flow. Parse payment terms string (e.g., 2/10-NET30) or use earlyPaymentPolicy input.",
            "properties": {
              "recommendedPaymentDate": {
                "type": "string",
                "description": "Optimal ISO 8601 payment date balancing DPO targets with discount capture. Earlier of (today + discountDays) or (dueDate - 2 days)."
              },
              "earlyPaymentDiscountAmount": {
                "type": "number",
                "description": "Savings in invoice currency if paid within discount window. 0 if no discount available."
              },
              "earlyPaymentDiscountPercentage": {
                "type": "number",
                "description": "Discount percentage (e.g., 2.0 for 2%). 0 if none."
              },
              "daysUntilDue": {
                "type": "integer",
                "description": "Calendar days until due. Negative = already overdue."
              },
              "discountWindowOpen": {
                "type": "boolean",
                "description": "True if early payment discount window is still active."
              },
              "cashFlowUrgency": {
                "type": "string",
                "description": "Payment urgency. OVERDUE = past due date. HIGH = due within 3 days.",
                "enum": [
                  "LOW",
                  "MEDIUM",
                  "HIGH",
                  "OVERDUE"
                ]
              },
              "dynamicDiscountingOpportunity": {
                "type": "boolean",
                "description": "True if favorable for dynamic discounting negotiation with vendor."
              }
            }
          },
          "glCodingSuggestions": {
            "type": "array",
            "description": "Per-line GL account code suggestions for ERP posting. Match line descriptions against glCodeMapping keywords. Fallback to PO glCode (MEDIUM) or category inference (LOW).",
            "items": {
              "type": "object",
              "required": [
                "lineNumber",
                "itemDescription",
                "suggestedGlCode",
                "confidence"
              ],
              "properties": {
                "lineNumber": {
                  "type": "integer"
                },
                "itemDescription": {
                  "type": "string"
                },
                "suggestedGlCode": {
                  "type": "string",
                  "description": "Recommended GL account code."
                },
                "accountName": {
                  "type": "string",
                  "description": "GL account name."
                },
                "confidence": {
                  "type": "string",
                  "description": "HIGH = keyword match; MEDIUM = PO glCode or category; LOW = best-guess fallback.",
                  "enum": [
                    "HIGH",
                    "MEDIUM",
                    "LOW"
                  ]
                },
                "basis": {
                  "type": "string",
                  "description": "Reason for this GL code suggestion."
                }
              }
            }
          },
          "vendorScorecard": {
            "type": "object",
            "description": "AI vendor performance scorecard. invoiceAccuracyScore = max(0, 100 - historicalDiscrepancyRate*1.5 - currentDiscrepancyCount*5). deliveryPerformanceScore = onTimeDeliveryRate or 50 if unknown. overallScore = accuracy*0.6 + delivery*0.4.",
            "properties": {
              "overallScore": {
                "type": "number",
                "description": "Composite vendor score 0-100."
              },
              "invoiceAccuracyScore": {
                "type": "number",
                "description": "Invoice accuracy score 0-100."
              },
              "deliveryPerformanceScore": {
                "type": "number",
                "description": "On-time delivery score 0-100."
              },
              "riskTrend": {
                "type": "string",
                "description": "DECLINING if openDisputeCount > 3. IMPROVING if historicalDiscrepancyRate < 5. Else STABLE.",
                "enum": [
                  "IMPROVING",
                  "STABLE",
                  "DECLINING",
                  "UNKNOWN"
                ]
              },
              "strategicRecommendation": {
                "type": "string",
                "description": ">80 = MAINTAIN; 60-80 = MONITOR; 40-60 = REVIEW; <40 = DELIST.",
                "enum": [
                  "MAINTAIN",
                  "MONITOR",
                  "REVIEW",
                  "DELIST"
                ]
              },
              "scorecardNotes": {
                "type": "string",
                "description": "Narrative explaining the score and recommendation."
              }
            }
          },
          "accrualRecommendation": {
            "type": "object",
            "description": "Accrual journal entry recommendation for goods received but not yet invoiced (GR/NI). Flag when GRN line has quantityReceived > 0 but no corresponding invoice line exists.",
            "properties": {
              "accrualRequired": {
                "type": "boolean",
                "description": "True if a GR/NI accrual entry should be posted."
              },
              "accrualAmount": {
                "type": "number",
                "description": "Total amount to accrue = sum of (quantityReceived × PO unitPrice) for unmatched GRN lines."
              },
              "currency": {
                "type": "string"
              },
              "accrualReason": {
                "type": "string",
                "description": "Explanation of why the accrual is needed."
              },
              "affectedLineNumbers": {
                "type": "array",
                "description": "PO line numbers driving the accrual.",
                "items": {
                  "type": "integer"
                }
              }
            }
          },
          "taxComplianceCheck": {
            "type": "object",
            "description": "Tax validation. expectedTaxAmount = subtotal × (standardTaxRate/100). isCompliant = |variance| ≤ max($1, subtotal×0.005). Skip if complianceRules not provided.",
            "properties": {
              "expectedTaxRate": {
                "type": "number",
                "description": "Expected tax rate % from complianceRules. Null if not configured."
              },
              "invoicedTaxRate": {
                "type": "number",
                "description": "Actual tax rate on invoice: taxAmount / subtotalAmount × 100."
              },
              "expectedTaxAmount": {
                "type": "number"
              },
              "invoicedTaxAmount": {
                "type": "number"
              },
              "taxVarianceAmount": {
                "type": "number",
                "description": "invoicedTaxAmount - expectedTaxAmount. Positive = over-taxed."
              },
              "isCompliant": {
                "type": "boolean"
              },
              "complianceNotes": {
                "type": "string"
              }
            }
          },
          "splitPaymentRecommendation": {
            "type": "object",
            "description": "Split payment analysis: approve clean lines immediately, hold disputed lines. Only populated when recommendation is RETURN_TO_VENDOR or ESCALATE_TO_AP and clean lines exist.",
            "properties": {
              "splitPaymentPossible": {
                "type": "boolean",
                "description": "True if some lines are clean and others disputed."
              },
              "approvedAmount": {
                "type": "number",
                "description": "Total for lines safe to pay now."
              },
              "disputedAmount": {
                "type": "number",
                "description": "Total for lines under dispute."
              },
              "approvedLineNumbers": {
                "type": "array",
                "items": {
                  "type": "integer"
                }
              },
              "disputedLineNumbers": {
                "type": "array",
                "items": {
                  "type": "integer"
                }
              },
              "splitReasoning": {
                "type": "string"
              }
            }
          },
          "slaStatus": {
            "type": "object",
            "description": "Invoice processing SLA tracking. invoiceAgeDays = today - invoiceDate. daysUntilDue = dueDate - today. urgencyLevel: <0 = CRITICAL(OVERDUE); 0-3 = HIGH; 4-7 = MEDIUM; 8+ = LOW.",
            "properties": {
              "invoiceAgeDays": {
                "type": "integer",
                "description": "Days since invoice date."
              },
              "daysUntilDue": {
                "type": "integer",
                "description": "Days until payment due. Negative = overdue."
              },
              "isOverdue": {
                "type": "boolean"
              },
              "urgencyLevel": {
                "type": "string",
                "enum": [
                  "LOW",
                  "MEDIUM",
                  "HIGH",
                  "CRITICAL"
                ]
              },
              "processingDeadline": {
                "type": "string",
                "description": "Latest processing date to meet payment terms (YYYY-MM-DD)."
              }
            }
          },
          "vendorCommunicationDraft": {
            "type": "string",
            "description": "Ready-to-send vendor dispute email. Only populate when recommendation = RETURN_TO_VENDOR. Include specific discrepancies, corrected figures, and resubmission instructions."
          },
          "fraudRiskIndicators": {
            "type": "array",
            "description": "Fraud signals detected. Empty array if none.",
            "items": {
              "type": "object",
              "properties": {
                "indicator": {
                  "type": "string",
                  "description": "e.g. BANK_DETAIL_CHANGE, DUPLICATE_INVOICE, ROUND_NUMBER_INVOICE, SPLIT_INVOICE_PATTERN, VELOCITY_ANOMALY."
                },
                "description": {
                  "type": "string"
                },
                "riskLevel": {
                  "type": "string",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH"
                  ]
                }
              }
            }
          },
          "reasoning": {
            "type": "string",
            "description": "Numbered compliance audit trail covering every step: document extraction, header match, line-item match, fraud check, tax compliance, payment intelligence, GL coding, vendor scorecard, accrual detection, split payment analysis, and routing decision."
          },
          "processingMetadata": {
            "type": "object",
            "properties": {
              "agentVersion": {
                "type": "string",
                "description": "Set to 2.0.0."
              },
              "processedAt": {
                "type": "string",
                "description": "ISO 8601 timestamp."
              },
              "documentsProcessed": {
                "type": "array",
                "description": "e.g. [PO, GRN, INVOICE, BATCH_CSV].",
                "items": {
                  "type": "string"
                }
              },
              "extractionTool": {
                "type": "string",
                "description": "Tool used for PDF extraction: DeepRAG, Analyze Files, or STRUCTURED_INPUT."
              },
              "toleranceApplied": {
                "type": "number"
              }
            }
          }
        }
      }

spec.entryPoints:
{
  "$schema": "https://cloud.uipath.com/draft/2024-12/entry-point",
  "$id": "entry-points.json",
  "entryPoints": [
    {
      "filePath": "content/agent.json",
      "uniqueId": "2860b2c5-0a04-4699-a7e3-5c06103e872a",
      "type": "agent",
      "input": {
        "type": "object",
        "required": [],
        "properties": {
          "processInstanceId": {
            "type": "string",
            "description": "Unique BPMN process instance ID from UiPath Maestro for traceability. Format: UUID or alphanumeric. Generate a trace ID if not provided."
          },
          "receiptFiles": {
            "type": "array",
            "description": "One or more receipts, purchase orders, invoices, or financial documents (Excel, PDF, CSV, image). The agent will automatically read and extract all data from ALL attached files using the Analyze Files tool. Supports .xlsx, .pdf, .csv, .png, .jpg, .tiff formats. This is the PRIMARY input — no manual data entry needed. Attach multiple files for batch processing or cross-referencing (e.g., a PO file + matching receipt + delivery note).",
            "items": {
              "$ref": "#/definitions/job-attachment"
            }
          },
          "invoiceFile": {
            "description": "Scanned or digital PDF invoice. When present, use DeepRAG (multi-page/complex) or Analyze Files (simple 1-5 page) to extract all invoice data before reconciliation. Takes precedence over the structured invoice field.",
            "$ref": "#/definitions/job-attachment"
          },
          "batchInvoiceFile": {
            "description": "CSV file of historical invoices from this vendor for duplicate detection and pattern analysis. Columns: invoiceNumber, vendorId, amount, date, status. Use the Batch Transform tool to process this file when provided.",
            "$ref": "#/definitions/job-attachment"
          },
          "purchaseOrder": {
            "type": "object",
            "description": "Purchase Order as extracted by RPA from the ERP. Must include header and line-item details.",
            "required": [
              "poNumber",
              "vendorId",
              "vendorName",
              "currency",
              "totalAmount",
              "lineItems"
            ],
            "properties": {
              "poNumber": {
                "type": "string",
                "description": "Unique PO reference number (e.g., PO-2026-00123)."
              },
              "vendorId": {
                "type": "string",
                "description": "Internal vendor master ID."
              },
              "vendorName": {
                "type": "string",
                "description": "Legal vendor name in ERP."
              },
              "orderDate": {
                "type": "string",
                "description": "PO creation date (YYYY-MM-DD)."
              },
              "currency": {
                "type": "string",
                "description": "ISO 4217 currency code (e.g., USD, EUR)."
              },
              "totalAmount": {
                "type": "number",
                "description": "Total approved PO amount excl. tax."
              },
              "taxAmount": {
                "type": "number",
                "description": "Tax on PO. Defaults to 0 if omitted."
              },
              "paymentTerms": {
                "type": "string",
                "description": "Payment terms (e.g., NET30, 2/10-NET30). Used for early payment discount parsing."
              },
              "costCenter": {
                "type": "string",
                "description": "Cost center or department code."
              },
              "category": {
                "type": "string",
                "description": "Spend category (IT, Facilities, Marketing, Services, Goods). Drives approval routing and GL coding."
              },
              "lineItems": {
                "type": "array",
                "description": "PO line items. Each represents an ordered SKU or service.",
                "items": {
                  "type": "object",
                  "required": [
                    "lineNumber",
                    "description",
                    "quantityOrdered",
                    "unitPrice",
                    "totalPrice"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer",
                      "description": "Sequential line number from 1."
                    },
                    "itemCode": {
                      "type": "string",
                      "description": "SKU or service code."
                    },
                    "description": {
                      "type": "string",
                      "description": "Item or service description."
                    },
                    "quantityOrdered": {
                      "type": "number",
                      "description": "Quantity ordered."
                    },
                    "unitPrice": {
                      "type": "number",
                      "description": "Agreed unit price in PO currency."
                    },
                    "totalPrice": {
                      "type": "number",
                      "description": "quantityOrdered x unitPrice."
                    },
                    "glCode": {
                      "type": "string",
                      "description": "Existing GL account code from ERP. Used as medium-confidence fallback for GL coding suggestions."
                    },
                    "deliveryDate": {
                      "type": "string",
                      "description": "Expected delivery date (YYYY-MM-DD)."
                    }
                  }
                }
              }
            }
          },
          "goodsReceiptNote": {
            "type": "object",
            "description": "GRN confirming physical receipt of goods or service completion. If absent for goods POs, flag GRN_NOT_RECEIVED and check for accrual needs.",
            "properties": {
              "grnNumber": {
                "type": "string",
                "description": "Unique GRN reference number."
              },
              "receiptDate": {
                "type": "string",
                "description": "Date goods/services were received (YYYY-MM-DD)."
              },
              "receivedBy": {
                "type": "string",
                "description": "Name or employee ID of receiver."
              },
              "lineItems": {
                "type": "array",
                "description": "Received line items. Match by lineNumber to PO. Used for 3-way match and accrual detection.",
                "items": {
                  "type": "object",
                  "required": [
                    "lineNumber",
                    "quantityReceived"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer",
                      "description": "PO line number."
                    },
                    "itemCode": {
                      "type": "string",
                      "description": "SKU or service code."
                    },
                    "description": {
                      "type": "string",
                      "description": "Received item description."
                    },
                    "quantityReceived": {
                      "type": "number",
                      "description": "Actual quantity received and accepted."
                    },
                    "condition": {
                      "type": "string",
                      "description": "GOOD, DAMAGED, PARTIAL, or REJECTED."
                    }
                  }
                }
              }
            }
          },
          "invoice": {
            "type": "object",
            "description": "Vendor invoice as structured data from RPA (email/EDI/portal). Optional if invoiceFile is provided — PDF extraction takes precedence.",
            "properties": {
              "invoiceNumber": {
                "type": "string",
                "description": "Vendor invoice number."
              },
              "invoiceDate": {
                "type": "string",
                "description": "Invoice issue date (YYYY-MM-DD)."
              },
              "dueDate": {
                "type": "string",
                "description": "Payment due date (YYYY-MM-DD). Used for SLA and payment intelligence calculations."
              },
              "vendorId": {
                "type": "string",
                "description": "Vendor ID on invoice. Must match PO vendorId."
              },
              "poReference": {
                "type": "string",
                "description": "PO number on invoice. Must match purchaseOrder.poNumber."
              },
              "currency": {
                "type": "string",
                "description": "ISO 4217 currency code on invoice."
              },
              "subtotalAmount": {
                "type": "number",
                "description": "Invoice subtotal before tax. Used for tax compliance check."
              },
              "taxAmount": {
                "type": "number",
                "description": "Tax charged on invoice."
              },
              "totalAmount": {
                "type": "number",
                "description": "Total due including tax."
              },
              "paymentTerms": {
                "type": "string",
                "description": "Payment terms on invoice. Compare against PO terms; flag conflicts."
              },
              "bankDetails": {
                "type": "object",
                "description": "Vendor bank details. Flag BANK_DETAIL_CHANGE if different from vendor master.",
                "properties": {
                  "bankName": {
                    "type": "string"
                  },
                  "accountNumber": {
                    "type": "string"
                  },
                  "routingNumber": {
                    "type": "string"
                  }
                }
              },
              "lineItems": {
                "type": "array",
                "description": "Invoice line items. Match by lineNumber or description against PO lines.",
                "items": {
                  "type": "object",
                  "required": [
                    "description",
                    "quantity",
                    "unitPrice",
                    "totalPrice"
                  ],
                  "properties": {
                    "lineNumber": {
                      "type": "integer"
                    },
                    "description": {
                      "type": "string"
                    },
                    "quantity": {
                      "type": "number"
                    },
                    "unitPrice": {
                      "type": "number"
                    },
                    "totalPrice": {
                      "type": "number"
                    }
                  }
                }
              }
            }
          },
          "approvalThresholds": {
            "type": "object",
            "description": "Approval thresholds and tolerance policies driving BPMN gateway routing.",
            "properties": {
              "autoApproveLimit": {
                "type": "number",
                "description": "Max invoice total for auto-approval without human review. Default: 1000."
              },
              "managerApprovalLimit": {
                "type": "number",
                "description": "Invoices above this need manager approval. Default: 10000."
              },
              "tolerancePercentage": {
                "type": "number",
                "description": "Acceptable variance % before flagging discrepancy. Default: 2."
              },
              "toleranceAmountFloor": {
                "type": "number",
                "description": "Minimum absolute difference that must also be exceeded to trigger discrepancy. Default: 5."
              }
            }
          },
          "vendorContext": {
            "type": "object",
            "description": "Vendor history and risk data from ERP/CRM. Powers vendor scorecard and fraud assessment.",
            "properties": {
              "riskRating": {
                "type": "string",
                "description": "Vendor risk: LOW, MEDIUM, HIGH, BLOCKED."
              },
              "historicalDiscrepancyRate": {
                "type": "number",
                "description": "% of past invoices with discrepancies (0-100). Used in scorecard."
              },
              "onTimeDeliveryRate": {
                "type": "number",
                "description": "% of POs delivered on time (0-100). Used in scorecard."
              },
              "isPreferredVendor": {
                "type": "boolean",
                "description": "True if on approved/preferred vendor list."
              },
              "openDisputeCount": {
                "type": "integer",
                "description": "Currently open disputes with this vendor."
              }
            }
          },
          "earlyPaymentPolicy": {
            "type": "object",
            "description": "Organization's early payment discount policy. Overrides terms parsed from invoice/PO payment terms string. Used to calculate payment intelligence output.",
            "properties": {
              "discountPercentage": {
                "type": "number",
                "description": "Discount % for early payment (e.g., 2 for 2%). Overrides parsed terms."
              },
              "discountDays": {
                "type": "integer",
                "description": "Days within which early payment discount applies (e.g., 10 for 2/10-NET30)."
              },
              "netDays": {
                "type": "integer",
                "description": "Total payment due days (e.g., 30 for NET30)."
              }
            }
          },
          "exchangeRates": {
            "type": "object",
            "description": "FX exchange rates for multi-currency normalization. Keys are ISO 4217 pairs joined by underscore (e.g., 'USD_EUR': 0.92). Provide when PO and invoice currencies differ.",
            "additionalProperties": {
              "type": "number"
            }
          },
          "glCodeMapping": {
            "type": "array",
            "description": "Organization GL code mapping rules for smart GL coding suggestions. Each entry maps keywords to a GL account code.",
            "items": {
              "type": "object",
              "required": [
                "keywords",
                "glCode",
                "accountName"
              ],
              "properties": {
                "keywords": {
                  "type": "array",
                  "description": "Keywords to match against line item descriptions (case-insensitive).",
                  "items": {
                    "type": "string"
                  }
                },
                "glCode": {
                  "type": "string",
                  "description": "GL account code to assign when keywords match."
                },
                "accountName": {
                  "type": "string",
                  "description": "Human-readable GL account name."
                },
                "category": {
                  "type": "string",
                  "description": "Spend category this GL code belongs to."
                }
              }
            }
          },
          "complianceRules": {
            "type": "object",
            "description": "Tax compliance rules for the transaction jurisdiction. Used to validate invoice tax amounts and flag non-compliant invoices.",
            "properties": {
              "jurisdiction": {
                "type": "string",
                "description": "Tax jurisdiction code (e.g., US-CA, UK, DE, AU)."
              },
              "standardTaxRate": {
                "type": "number",
                "description": "Expected tax rate % (e.g., 10 for 10% GST, 20 for 20% VAT)."
              },
              "taxExemptCategories": {
                "type": "array",
                "description": "Spend categories exempt from standard tax (e.g., Healthcare, Education). If PO category is exempt, expected tax = 0.",
                "items": {
                  "type": "string"
                }
              }
            }
          },
          "previousInvoiceNumbers": {
            "type": "array",
            "description": "Array of recent invoice numbers (last 90 days) from this vendor in ERP. Used for duplicate detection when batchInvoiceFile is not provided.",
            "items": {
              "type": "string"
            }
          },
          "processContext": {
            "type": "string",
            "description": "Free-text notes from upstream BPMN tasks or RPA robots (e.g., 'Invoice arrived 5 days late', 'GRN flagged partial delivery'). Used for contextual reasoning."
          }
        },
        "definitions": {
          "job-attachment": {
            "type": "object",
            "required": [
              "ID"
            ],
            "x-uipath-resource-kind": "JobAttachment",
            "properties": {
              "ID": {
                "type": "string",
                "description": "Orchestrator attachment key"
              },
              "FullName": {
                "type": "string",
                "description": "File name"
              },
              "MimeType": {
                "type": "string",
                "description": "The MIME type of the content, such as \"application/json\" or \"image/png\""
              },
              "Metadata": {
                "type": "object",
                "description": "Dictionary<string, string> of metadata",
                "additionalProperties": {
                  "type": "string"
                }
              }
            }
          }
        }
      },
      "output": {
        "type": "object",
        "required": [
          "matchStatus",
          "recommendation",
          "confidenceScore",
          "nextBpmnGateway",
          "reconciliationSummary",
          "discrepancies",
          "actionItems",
          "reasoning"
        ],
        "properties": {
          "processInstanceId": {
            "type": "string",
            "description": "Echo of processInstanceId from input for BPMN correlation. Generate a trace ID if input was not provided."
          },
          "matchStatus": {
            "type": "string",
            "description": "3-way match result. FULL_MATCH = exact alignment. WITHIN_TOLERANCE = variance within threshold. PARTIAL_MATCH = some lines match. MISMATCH = significant variance outside tolerance. CRITICAL_EXCEPTION = fraud, blocked vendor, duplicate, or missing critical document.",
            "enum": [
              "FULL_MATCH",
              "WITHIN_TOLERANCE",
              "PARTIAL_MATCH",
              "MISMATCH",
              "CRITICAL_EXCEPTION"
            ]
          },
          "recommendation": {
            "type": "string",
            "description": "Recommended next action for the BPMN gateway. AUTO_APPROVE = post and schedule payment. RETURN_TO_VENDOR = request corrected invoice. ESCALATE_TO_AP = AP team manual review. ESCALATE_TO_MANAGER = budget owner approval. BLOCK_PAYMENT = halt for fraud/compliance review.",
            "enum": [
              "AUTO_APPROVE",
              "RETURN_TO_VENDOR",
              "ESCALATE_TO_AP",
              "ESCALATE_TO_MANAGER",
              "BLOCK_PAYMENT"
            ]
          },
          "confidenceScore": {
            "type": "number",
            "description": "Agent confidence 0-100. Reduce by 20 for incomplete PDF extraction. Reduce by 10 per missing optional document. Scores below 60 should trigger human review."
          },
          "nextBpmnGateway": {
            "type": "string",
            "description": "Exact Maestro BPMN sequence flow label. Must be one of: auto_approve_path, ap_review_path, manager_approval_path, vendor_dispute_path, fraud_hold_path."
          },
          "reconciliationSummary": {
            "type": "object",
            "description": "Financial summary of the 3-way match.",
            "required": [
              "poAmount",
              "invoiceAmount",
              "varianceAmount",
              "variancePercentage",
              "currency",
              "isWithinTolerance"
            ],
            "properties": {
              "poAmount": {
                "type": "number",
                "description": "PO total excl. tax — the baseline reference amount."
              },
              "grnAmount": {
                "type": "number",
                "description": "Value of goods/services confirmed received via GRN. Null if no GRN."
              },
              "invoiceAmount": {
                "type": "number",
                "description": "Invoice total excl. tax."
              },
              "varianceAmount": {
                "type": "number",
                "description": "invoiceAmount minus poAmount. Positive = overbilled."
              },
              "variancePercentage": {
                "type": "number",
                "description": "Variance as % of PO amount. Positive = overbilled."
              },
              "currency": {
                "type": "string",
                "description": "Currency code for all amounts."
              },
              "isWithinTolerance": {
                "type": "boolean",
                "description": "True if variancePercentage is within configured tolerancePercentage."
              }
            }
          },
          "discrepancies": {
            "type": "array",
            "description": "All discrepancies found. Empty array if FULL_MATCH.",
            "items": {
              "type": "object",
              "required": [
                "discrepancyId",
                "type",
                "severity",
                "description"
              ],
              "properties": {
                "discrepancyId": {
                  "type": "string",
                  "description": "Sequential ID e.g. DISC-001."
                },
                "type": {
                  "type": "string",
                  "enum": [
                    "PRICE_VARIANCE",
                    "QUANTITY_VARIANCE",
                    "LINE_ITEM_MISSING",
                    "EXTRA_LINE_ITEM",
                    "CURRENCY_MISMATCH",
                    "VENDOR_MISMATCH",
                    "PO_REFERENCE_MISSING",
                    "DUPLICATE_INVOICE",
                    "BANK_DETAIL_CHANGE",
                    "TAX_DISCREPANCY",
                    "PAYMENT_TERMS_CONFLICT",
                    "GRN_NOT_RECEIVED",
                    "SPLIT_INVOICE_PATTERN",
                    "VELOCITY_ANOMALY"
                  ]
                },
                "severity": {
                  "type": "string",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH",
                    "CRITICAL"
                  ]
                },
                "lineNumber": {
                  "type": "integer",
                  "description": "PO line number. Null for header-level discrepancies."
                },
                "description": {
                  "type": "string",
                  "description": "Human-readable discrepancy explanation."
                },
                "poValue": {
                  "type": "string",
                  "description": "Expected value from PO."
                },
                "invoiceValue": {
                  "type": "string",
                  "description": "Actual value from invoice."
                },
                "impactAmount": {
                  "type": "number",
                  "description": "Financial impact in PO currency. Positive = overbilled."
                }
              }
            }
          },
          "actionItems": {
            "type": "array",
            "description": "Ordered action items for the next actor in the BPMN process.",
            "items": {
              "type": "object",
              "required": [
                "actionId",
                "owner",
                "priority",
                "description"
              ],
              "properties": {
                "actionId": {
                  "type": "string",
                  "description": "Sequential ID e.g. ACT-001."
                },
                "owner": {
                  "type": "string",
                  "description": "AP_TEAM, MANAGER, VENDOR, RPA_ROBOT, AGENT, or SYSTEM."
                },
                "priority": {
                  "type": "string",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH",
                    "URGENT"
                  ]
                },
                "description": {
                  "type": "string"
                },
                "dueDate": {
                  "type": "string",
                  "description": "Suggested due date (YYYY-MM-DD)."
                }
              }
            }
          },
          "paymentIntelligence": {
            "type": "object",
            "description": "Smart payment timing to capture early payment discounts and manage cash flow. Parse payment terms string (e.g., 2/10-NET30) or use earlyPaymentPolicy input.",
            "properties": {
              "recommendedPaymentDate": {
                "type": "string",
                "description": "Optimal ISO 8601 payment date balancing DPO targets with discount capture. Earlier of (today + discountDays) or (dueDate - 2 days)."
              },
              "earlyPaymentDiscountAmount": {
                "type": "number",
                "description": "Savings in invoice currency if paid within discount window. 0 if no discount available."
              },
              "earlyPaymentDiscountPercentage": {
                "type": "number",
                "description": "Discount percentage (e.g., 2.0 for 2%). 0 if none."
              },
              "daysUntilDue": {
                "type": "integer",
                "description": "Calendar days until due. Negative = already overdue."
              },
              "discountWindowOpen": {
                "type": "boolean",
                "description": "True if early payment discount window is still active."
              },
              "cashFlowUrgency": {
                "type": "string",
                "description": "Payment urgency. OVERDUE = past due date. HIGH = due within 3 days.",
                "enum": [
                  "LOW",
                  "MEDIUM",
                  "HIGH",
                  "OVERDUE"
                ]
              },
              "dynamicDiscountingOpportunity": {
                "type": "boolean",
                "description": "True if favorable for dynamic discounting negotiation with vendor."
              }
            }
          },
          "glCodingSuggestions": {
            "type": "array",
            "description": "Per-line GL account code suggestions for ERP posting. Match line descriptions against glCodeMapping keywords. Fallback to PO glCode (MEDIUM) or category inference (LOW).",
            "items": {
              "type": "object",
              "required": [
                "lineNumber",
                "itemDescription",
                "suggestedGlCode",
                "confidence"
              ],
              "properties": {
                "lineNumber": {
                  "type": "integer"
                },
                "itemDescription": {
                  "type": "string"
                },
                "suggestedGlCode": {
                  "type": "string",
                  "description": "Recommended GL account code."
                },
                "accountName": {
                  "type": "string",
                  "description": "GL account name."
                },
                "confidence": {
                  "type": "string",
                  "description": "HIGH = keyword match; MEDIUM = PO glCode or category; LOW = best-guess fallback.",
                  "enum": [
                    "HIGH",
                    "MEDIUM",
                    "LOW"
                  ]
                },
                "basis": {
                  "type": "string",
                  "description": "Reason for this GL code suggestion."
                }
              }
            }
          },
          "vendorScorecard": {
            "type": "object",
            "description": "AI vendor performance scorecard. invoiceAccuracyScore = max(0, 100 - historicalDiscrepancyRate*1.5 - currentDiscrepancyCount*5). deliveryPerformanceScore = onTimeDeliveryRate or 50 if unknown. overallScore = accuracy*0.6 + delivery*0.4.",
            "properties": {
              "overallScore": {
                "type": "number",
                "description": "Composite vendor score 0-100."
              },
              "invoiceAccuracyScore": {
                "type": "number",
                "description": "Invoice accuracy score 0-100."
              },
              "deliveryPerformanceScore": {
                "type": "number",
                "description": "On-time delivery score 0-100."
              },
              "riskTrend": {
                "type": "string",
                "description": "DECLINING if openDisputeCount > 3. IMPROVING if historicalDiscrepancyRate < 5. Else STABLE.",
                "enum": [
                  "IMPROVING",
                  "STABLE",
                  "DECLINING",
                  "UNKNOWN"
                ]
              },
              "strategicRecommendation": {
                "type": "string",
                "description": ">80 = MAINTAIN; 60-80 = MONITOR; 40-60 = REVIEW; <40 = DELIST.",
                "enum": [
                  "MAINTAIN",
                  "MONITOR",
                  "REVIEW",
                  "DELIST"
                ]
              },
              "scorecardNotes": {
                "type": "string",
                "description": "Narrative explaining the score and recommendation."
              }
            }
          },
          "accrualRecommendation": {
            "type": "object",
            "description": "Accrual journal entry recommendation for goods received but not yet invoiced (GR/NI). Flag when GRN line has quantityReceived > 0 but no corresponding invoice line exists.",
            "properties": {
              "accrualRequired": {
                "type": "boolean",
                "description": "True if a GR/NI accrual entry should be posted."
              },
              "accrualAmount": {
                "type": "number",
                "description": "Total amount to accrue = sum of (quantityReceived × PO unitPrice) for unmatched GRN lines."
              },
              "currency": {
                "type": "string"
              },
              "accrualReason": {
                "type": "string",
                "description": "Explanation of why the accrual is needed."
              },
              "affectedLineNumbers": {
                "type": "array",
                "description": "PO line numbers driving the accrual.",
                "items": {
                  "type": "integer"
                }
              }
            }
          },
          "taxComplianceCheck": {
            "type": "object",
            "description": "Tax validation. expectedTaxAmount = subtotal × (standardTaxRate/100). isCompliant = |variance| ≤ max($1, subtotal×0.005). Skip if complianceRules not provided.",
            "properties": {
              "expectedTaxRate": {
                "type": "number",
                "description": "Expected tax rate % from complianceRules. Null if not configured."
              },
              "invoicedTaxRate": {
                "type": "number",
                "description": "Actual tax rate on invoice: taxAmount / subtotalAmount × 100."
              },
              "expectedTaxAmount": {
                "type": "number"
              },
              "invoicedTaxAmount": {
                "type": "number"
              },
              "taxVarianceAmount": {
                "type": "number",
                "description": "invoicedTaxAmount - expectedTaxAmount. Positive = over-taxed."
              },
              "isCompliant": {
                "type": "boolean"
              },
              "complianceNotes": {
                "type": "string"
              }
            }
          },
          "splitPaymentRecommendation": {
            "type": "object",
            "description": "Split payment analysis: approve clean lines immediately, hold disputed lines. Only populated when recommendation is RETURN_TO_VENDOR or ESCALATE_TO_AP and clean lines exist.",
            "properties": {
              "splitPaymentPossible": {
                "type": "boolean",
                "description": "True if some lines are clean and others disputed."
              },
              "approvedAmount": {
                "type": "number",
                "description": "Total for lines safe to pay now."
              },
              "disputedAmount": {
                "type": "number",
                "description": "Total for lines under dispute."
              },
              "approvedLineNumbers": {
                "type": "array",
                "items": {
                  "type": "integer"
                }
              },
              "disputedLineNumbers": {
                "type": "array",
                "items": {
                  "type": "integer"
                }
              },
              "splitReasoning": {
                "type": "string"
              }
            }
          },
          "slaStatus": {
            "type": "object",
            "description": "Invoice processing SLA tracking. invoiceAgeDays = today - invoiceDate. daysUntilDue = dueDate - today. urgencyLevel: <0 = CRITICAL(OVERDUE); 0-3 = HIGH; 4-7 = MEDIUM; 8+ = LOW.",
            "properties": {
              "invoiceAgeDays": {
                "type": "integer",
                "description": "Days since invoice date."
              },
              "daysUntilDue": {
                "type": "integer",
                "description": "Days until payment due. Negative = overdue."
              },
              "isOverdue": {
                "type": "boolean"
              },
              "urgencyLevel": {
                "type": "string",
                "enum": [
                  "LOW",
                  "MEDIUM",
                  "HIGH",
                  "CRITICAL"
                ]
              },
              "processingDeadline": {
                "type": "string",
                "description": "Latest processing date to meet payment terms (YYYY-MM-DD)."
              }
            }
          },
          "vendorCommunicationDraft": {
            "type": "string",
            "description": "Ready-to-send vendor dispute email. Only populate when recommendation = RETURN_TO_VENDOR. Include specific discrepancies, corrected figures, and resubmission instructions."
          },
          "fraudRiskIndicators": {
            "type": "array",
            "description": "Fraud signals detected. Empty array if none.",
            "items": {
              "type": "object",
              "properties": {
                "indicator": {
                  "type": "string",
                  "description": "e.g. BANK_DETAIL_CHANGE, DUPLICATE_INVOICE, ROUND_NUMBER_INVOICE, SPLIT_INVOICE_PATTERN, VELOCITY_ANOMALY."
                },
                "description": {
                  "type": "string"
                },
                "riskLevel": {
                  "type": "string",
                  "enum": [
                    "LOW",
                    "MEDIUM",
                    "HIGH"
                  ]
                }
              }
            }
          },
          "reasoning": {
            "type": "string",
            "description": "Numbered compliance audit trail covering every step: document extraction, header match, line-item match, fraud check, tax compliance, payment intelligence, GL coding, vendor scorecard, accrual detection, split payment analysis, and routing decision."
          },
          "processingMetadata": {
            "type": "object",
            "properties": {
              "agentVersion": {
                "type": "string",
                "description": "Set to 2.0.0."
              },
              "processedAt": {
                "type": "string",
                "description": "ISO 8601 timestamp."
              },
              "documentsProcessed": {
                "type": "array",
                "description": "e.g. [PO, GRN, INVOICE, BATCH_CSV].",
                "items": {
                  "type": "string"
                }
              },
              "extractionTool": {
                "type": "string",
                "description": "Tool used for PDF extraction: DeepRAG, Analyze Files, or STRUCTURED_INPUT."
              },
              "toleranceApplied": {
                "type": "number"
              }
            }
          }
        }
      }
    }
  ]
